:root {
    --primary-color: #333;
    --accent-color: #4CAF50;
    --background-color: #222;
    --text-color: #fff;
    --border-radius: 16px;
    --box-shadow: 0 0 10px rgba(0, 0, 0, 0.2);
    --spacing: 20px;
}

body {
    font-family: 'Montserrat', sans-serif;
    background-color: var(--background-color);
    color: var(--text-color);
    margin: 0;
    padding: 0;
}

header {
    background-color: var(--primary-color);
    padding: var(--spacing);
    text-align: center;
}

header h1 {
    font-weight: 800;
    font-size: 36px;
    margin-bottom: 10px;
}

header p {
    font-size: 18px;
    color: #ccc;
}

main {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: var(--spacing);
}

section {
    background-color: var(--primary-color);
    padding: var(--spacing);
    border-radius: var(--border-radius);
    box-shadow: var(--box-shadow);
    margin-bottom: var(--spacing);
}

h2 {
    font-weight: 600;
    font-size: 24px;
    margin-bottom: 10px;
}

button {
    background-color: var(--accent-color);
    color: var(--text-color);
    border: none;
    padding: 10px 20px;
    border-radius: var(--border-radius);
    cursor: pointer;
}

button:hover {
    transform: scale(1.05);
    box-shadow: 0 0 10px rgba(0, 0, 0, 0.4);
}

button:active {
    transform: scale(0.96);
}

input[type="number"] {
    width: 50px;
    height: 30px;
    font-size: 18px;
    padding: 10px;
    border: none;
    border-radius: var(--border-radius);
}

input[type="number"]:focus {
    outline: none;
    box-shadow: 0 0 10px rgba(0, 0, 0, 0.4);
}

#timer-container {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

#charts-container {
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
}

#integrations-container {
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
}

#sounds-container {
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
}

#lockdown-mode-toggle {
    background-color: var(--accent-color);
    color: var(--text-color);
    border: none;
    padding: 10px 20px;
    border-radius: var(--border-radius);
    cursor: pointer;
}

#lockdown-mode-toggle:hover {
    transform: scale(1.05);
    box-shadow: 0 0 10px rgba(0, 0, 0, 0.4);
}

#lockdown-mode-toggle:active {
    transform: scale(0.96);
}

/* Animated background */
body::before {
    content: "";
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: radial-gradient(50% 50% at 50% 50%, #333, #222);
    background-size: 200% 200%;
    animation: background-animation 10s ease infinite;
    z-index: -1;
}

@keyframes background-animation {
    0% {
        background-position: 0% 0%;
    }
    100% {
        background-position: 100% 100%;
    }
}

/* Page-load animations */
@keyframes fade-up {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

@keyframes slide-in {
    from {
        opacity: 0;
        transform: translateX(20px);
    }
    to {
        opacity: 1;
        transform: translateX(0);
    }
}

header {
    animation: fade-up 0.5s ease-out 0.5s forwards;
}

main {
    animation: slide-in 0.5s ease-out 1s forwards;
}

section {
    animation: fade-up 0.5s ease-out 1.5s forwards;
}

/* IntersectionObserver scroll reveals */
section {
    opacity: 0;
    transform: translateY(20px);
}

section.visible {
    opacity: 1;
    transform: translateY(0);
    transition: opacity 0.5s ease-out, transform 0.5s ease-out;
}

/* Styled scrollbars */
::-webkit-scrollbar {
    width: 10px;
    height: 10px;
}

::-webkit-scrollbar-thumb {
    background-color: var(--accent-color);
    border-radius: 10px;
}

::-webkit-scrollbar-track {
    background-color: var(--primary-color);
}

/* Selection color */
::selection {
    background-color: var(--accent-color);
}

// Get elements
const workDurationInput = document.getElementById('work-duration');
const breakDurationInput = document.getElementById('break-duration');
const startTimerButton = document.getElementById('start-timer');
const stopTimerButton = document.getElementById('stop-timer');
const timerTitle = document.getElementById('timer-title');
const lockdownModeToggle = document.getElementById('lockdown-mode-toggle');

// Initialize variables
let workDuration = parseInt(workDurationInput.value) * 60;
let breakDuration = parseInt(breakDurationInput.value) * 60;
let timerInterval;
let isWorkSession = true;
let isLockdownMode = false;

// Add event listeners
startTimerButton.addEventListener('click', startTimer);
stopTimerButton.addEventListener('click', stopTimer);
lockdownModeToggle.addEventListener('click', toggleLockdownMode);
workDurationInput.addEventListener('input', updateWorkDuration);
breakDurationInput.addEventListener('input', updateBreakDuration);

// Start timer
function startTimer() {
    timerInterval = setInterval(updateTimer, 1000);
    isWorkSession = true;
    workDuration = parseInt(workDurationInput.value) * 60;
    timerTitle.textContent = 'Work Session';
}

// Stop timer
function stopTimer() {
    clearInterval(timerInterval);
}

// Update timer
function updateTimer() {
    if (isWorkSession) {
        workDuration--;
        if (workDuration <= 0) {
            isWorkSession = false;
            breakDuration = parseInt(breakDurationInput.value) * 60;
            timerTitle.textContent = 'Break Session';
        }
    } else {
        breakDuration--;
        if (breakDuration <= 0) {
            isWorkSession = true;
            workDuration = parseInt(workDurationInput.value) * 60;
            timerTitle.textContent = 'Work Session';
        }
    }
    const minutes = Math.floor((isWorkSession ? workDuration : breakDuration) / 60);
    const seconds = (isWorkSession ? workDuration : breakDuration) % 60;
    timerTitle.textContent += ` (${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')})`;
}

// Update work duration
function updateWorkDuration() {
    workDuration = parseInt(workDurationInput.value) * 60;
}

// Update break duration
function updateBreakDuration() {
    breakDuration = parseInt(breakDurationInput.value) * 60;
}

// Toggle lockdown mode
function toggleLockdownMode() {
    isLockdownMode = !isLockdownMode;
    if (isLockdownMode) {
        lockdownModeToggle.textContent = 'Lockdown Mode: ON';
        // Restrict access to distracting websites and applications
        // This can be implemented using a browser extension or a custom solution
    } else {
        lockdownModeToggle.textContent = 'Lockdown Mode: OFF';
    }
}
